Javascript.validate:
var value = Services.getValue(BalanceOfTotalPrice.dataBinding);	      
var maxVal = 999999.99;
var err = validateCurrencyValue(value, maxVal);
if( null == err )
{ Services.setValue(BalanceOfTotalPrice.dataBinding, WPU.formatToTwoDP(value));
}
return err;

Javascript.miscCode:
function DefaultCurrency90() {}
DefaultCurrency90.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency90.tabIndex = -1;
DefaultCurrency90.maxLength = 1;
DefaultCurrency90.isReadOnly = function(){return true;}
DefaultCurrency90.isTemporary = function(){return true;}
DefaultCurrency90.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency90.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
